-- ============================================================
-- 完整气象数据库 SQL（正确执行顺序）
-- ============================================================

SET NAMES utf8mb4;
SET FOREIGN_KEY_CHECKS = 0;
SET SQL_MODE = "";

-- ════════════════════════════════════════════════════
-- STEP 1  建表
-- ════════════════════════════════════════════════════

DROP TABLE IF EXISTS `weather_data`;
CREATE TABLE `weather_data` (
  `station_code`              VARCHAR(50)   NOT NULL DEFAULT 'UNKNOWN' COMMENT '气象站点编码',
  `granularity`               TINYINT       NOT NULL                   COMMENT '采集颗粒度: 1=15分钟 2=小时 3=天',
  `record_time`               DATETIME      NOT NULL                   COMMENT '数据采集时间点',
  `avg_temperature`           DECIMAL(7,2)  DEFAULT NULL               COMMENT '平均气温(°C)',
  `precipitation`             DECIMAL(8,2)  DEFAULT NULL               COMMENT '降水量(mm)',
  `rain_sum`                  DECIMAL(8,2)  DEFAULT NULL               COMMENT '降雨量(mm)',
  `snow_sum`                  DECIMAL(8,2)  DEFAULT NULL               COMMENT '降雪量(mm)',
  `max_continuous_wind_speed` DECIMAL(6,2)  DEFAULT NULL               COMMENT '风速(m/s)',
  `windgusts_max`             DECIMAL(6,2)  DEFAULT NULL               COMMENT '阵风风速(m/s)',
  `winddirection_dominant`    SMALLINT      DEFAULT NULL               COMMENT '风向(°)',
  `shortwave_radiation_sum`   DECIMAL(8,2)  DEFAULT NULL               COMMENT '短波辐射(W/m²)',
  `create_time`               TIMESTAMP     DEFAULT CURRENT_TIMESTAMP  COMMENT '入库时间',
  PRIMARY KEY (`station_code`, `granularity`, `record_time`)
) ENGINE=INNODB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='气象站点数据表';

DROP TABLE IF EXISTS `weather_directory`;
CREATE TABLE `weather_directory` (
  `id`            INT           NOT NULL AUTO_INCREMENT                COMMENT '主键',
  `province`      VARCHAR(50)   NOT NULL                               COMMENT '省份',
  `city`          VARCHAR(50)   NOT NULL                               COMMENT '城市',
  `station_code`  VARCHAR(50)   NOT NULL DEFAULT 'UNKNOWN'             COMMENT '气象站点编码',
  `granularity`   TINYINT       NOT NULL                               COMMENT '采集颗粒度: 1=15分钟 2=小时 3=天',
  `start_time`    DATETIME      NOT NULL                               COMMENT '采集起始时间',
  `end_time`      DATETIME      NOT NULL                               COMMENT '采集结束时间',
  `total_count`   INT           NOT NULL DEFAULT 0                     COMMENT '数据总条数',
  `update_time`   TIMESTAMP     NULL ON UPDATE CURRENT_TIMESTAMP       COMMENT '最后更新时间',
  `create_time`   TIMESTAMP     DEFAULT CURRENT_TIMESTAMP              COMMENT '创建时间',
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_prov_city_station_gran` (`province`, `city`, `station_code`, `granularity`),
  INDEX `idx_province_city` (`province`, `city`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='气象站点目录索引表';

DROP TABLE IF EXISTS `station_info`;
CREATE TABLE `station_info` (
  `station_code`  VARCHAR(50)  NOT NULL  COMMENT '站点编码',
  `province`      VARCHAR(50)  NOT NULL  COMMENT '省份',
  `city`          VARCHAR(50)  NOT NULL  COMMENT '城市',
  `granularity`   TINYINT      NOT NULL  DEFAULT 2 COMMENT '颗粒度',
  `create_time`   TIMESTAMP    DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`station_code`, `granularity`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='站点省市映射表';


-- ════════════════════════════════════════════════════
-- STEP 2  插入初始数据（ST000001 + ST000002初始 + ST000003）
-- ════════════════════════════════════════════════════

-- ── ST000001 河北邢台 11160 条 ──────────────────────

-- ── ST000002 天津 8760 条（初始）───────────────────

-- ── ST000003 北京 11160 条 ─────────────────────────

-- ════════════════════════════════════════════════════
-- STEP 3  复合主键已保证唯一性，无需额外建唯一键
-- ════════════════════════════════════════════════════

-- ════════════════════════════════════════════════════
-- STEP 4  建触发器（INSERT 后自动从 station_info 查省市同步目录）
-- 新增站点只需在 station_info 插入一行，目录自动建立
-- ════════════════════════════════════════════════════

DROP TRIGGER IF EXISTS `trg_weather_data_after_insert`;

DELIMITER $$

CREATE TRIGGER `trg_weather_data_after_insert`
AFTER INSERT ON `weather_data`
FOR EACH ROW
BEGIN
  DECLARE v_province VARCHAR(50) DEFAULT 'UNKNOWN';
  DECLARE v_city     VARCHAR(50) DEFAULT 'UNKNOWN';

  -- 从 station_info 取省市名称
  SELECT province, city INTO v_province, v_city
  FROM station_info
  WHERE station_code = NEW.station_code
    AND granularity  = NEW.granularity
  LIMIT 1;

  IF EXISTS (
    SELECT 1 FROM `weather_directory`
    WHERE `station_code` = NEW.station_code
      AND `granularity`  = NEW.granularity
  ) THEN

    -- 目录已存在：更新 end_time（只往后推）、total_count +1
    UPDATE `weather_directory`
    SET
      `end_time`    = GREATEST(`end_time`, NEW.record_time),
      `total_count` = `total_count` + 1
    WHERE `station_code` = NEW.station_code
      AND `granularity`  = NEW.granularity;

  ELSE

    -- 目录不存在：自动新建，省市从 station_info 取
       `start_time`, `end_time`, `total_count`)
    VALUES
      (v_province, v_city, NEW.station_code, NEW.granularity,
       NEW.record_time, NEW.record_time, 1);

  END IF;

END$$

DELIMITER ;

-- ════════════════════════════════════════════════════
-- STEP 5  初始化目录（从 weather_data 自动计算，无需手动观察）
-- ════════════════════════════════════════════════════

   `start_time`, `end_time`, `total_count`)
SELECT
  COALESCE(s.province, 'UNKNOWN') AS province,
  COALESCE(s.city,     'UNKNOWN') AS city,
  d.station_code,
  d.granularity,
  MIN(d.record_time) AS start_time,
  MAX(d.record_time) AS end_time,
  COUNT(*)           AS total_count
FROM `weather_data` d
LEFT JOIN `station_info` s
  ON d.station_code = s.station_code
  AND d.granularity = s.granularity
GROUP BY d.station_code, d.granularity
ON DUPLICATE KEY UPDATE
  `start_time`  = VALUES(`start_time`),
  `end_time`    = VALUES(`end_time`),
  `total_count` = VALUES(`total_count`);

-- ════════════════════════════════════════════════════
-- STEP 6  插入 ST000002 补充数据（触发器自动更新目录）
-- 验证：导入后 ST000002 的 end_time 应自动更新至 2026-04-10 23:00
-- ════════════════════════════════════════════════════


SET FOREIGN_KEY_CHECKS = 1;

-- ════════════════════════════════════════════════════
-- 完成！新增站点：先在 station_info 插一行，再导入数据即可
